import React, { useState } from 'react';
import api from '../utils/api';
import { toast } from 'react-toastify';

/**
 * Reusable billing card — shows bill details and a Pay Now button.
 *
 * Props:
 *   type        : 'blood' | 'consultation'
 *   item        : the BloodRequest or Appointment object
 *   onPaid      : callback after successful payment
 *   canPay      : boolean — whether the current user can pay
 */
export default function BillingCard({ type, item, onPaid, canPay }) {
  const [paying, setPaying] = useState(false);

  if (!item) return null;

  const isPaid = item.paymentStatus === 'paid';

  // A valid charge requires totalAmount to be a positive number
  const hasValidCharge = item.totalAmount && item.totalAmount > 0;

  // Only show billing card for the correct statuses
  const showForBlood        = type === 'blood'        && (item.status === 'approved' || item.status === 'fulfilled');
  const showForConsultation = type === 'consultation' && item.status === 'completed';
  if (!showForBlood && !showForConsultation) return null;

  // Pay button is shown only when: charge exists, not yet paid, and user has permission
  const isPaymentEligible = hasValidCharge && !isPaid && canPay;

  // Informational message when payment is not available
  const statusMessage = (() => {
    if (isPaid) return null;
    if (!hasValidCharge) {
      return type === 'blood' ? 'Awaiting pricing from admin' : 'Awaiting fee update';
    }
    return null;
  })();

  const handlePay = async () => {
    if (!hasValidCharge) {
      toast.error('No charges defined for this item');
      return;
    }
    if (!window.confirm(`Confirm payment of $${item.totalAmount?.toFixed(2)}?`)) return;
    setPaying(true);
    try {
      const endpoint =
        type === 'blood'
          ? `/billing/blood/${item._id}/pay`
          : `/billing/appointment/${item._id}/pay`;
      await api.post(endpoint);
      toast.success('Payment successful');
      onPaid && onPaid();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Payment failed');
    } finally {
      setPaying(false);
    }
  };

  return (
    <div
      style={{
        marginTop: 8,
        padding: '10px 14px',
        borderRadius: 8,
        background: isPaid ? '#f0fdf4' : hasValidCharge ? '#fffbeb' : '#f3f4f6',
        border: `1px solid ${isPaid ? '#bbf7d0' : hasValidCharge ? '#fde68a' : '#d1d5db'}`,
        fontSize: '0.8rem',
      }}
    >
      <div className="d-flex align-items-center justify-content-between flex-wrap gap-2">
        {/* Charge details */}
        <div>
          {type === 'blood' ? (
            hasValidCharge ? (
              <>
                <span style={{ color: 'var(--text-muted)' }}>
                  {item.units} unit(s) &times; ${item.pricePerUnit?.toFixed(2) ?? '0.00'}
                  {item.emergencyCharge > 0 && ` + $${item.emergencyCharge?.toFixed(2)} service charge`}
                </span>
                <div style={{ fontWeight: 700, fontSize: '0.9rem', marginTop: 2 }}>
                  Total: ${item.totalAmount?.toFixed(2)}
                </div>
              </>
            ) : (
              <span style={{ color: 'var(--text-muted)', fontStyle: 'italic' }}>
                No charges applicable
              </span>
            )
          ) : (
            hasValidCharge ? (
              <>
                <span style={{ color: 'var(--text-muted)' }}>Consultation fee</span>
                <div style={{ fontWeight: 700, fontSize: '0.9rem', marginTop: 2 }}>
                  Total: ${item.totalAmount?.toFixed(2)}
                </div>
              </>
            ) : (
              <span style={{ color: 'var(--text-muted)', fontStyle: 'italic' }}>
                No charges applicable
              </span>
            )
          )}
        </div>

        {/* Status badge + action */}
        <div className="d-flex align-items-center gap-2">
          {isPaid ? (
            <span className="badge bg-success" style={{ fontSize: '0.75rem' }}>
              <i className="bi bi-check-circle me-1" />Paid
            </span>
          ) : hasValidCharge ? (
            <span className="badge bg-warning text-dark" style={{ fontSize: '0.75rem' }}>
              <i className="bi bi-clock me-1" />Pending
            </span>
          ) : (
            <span className="badge bg-secondary" style={{ fontSize: '0.75rem' }}>
              <i className="bi bi-dash-circle me-1" />No Charge
            </span>
          )}

          {statusMessage && (
            <span style={{ fontSize: '0.7rem', color: '#6b7280', fontStyle: 'italic' }}>
              {statusMessage}
            </span>
          )}

          {isPaymentEligible && (
            <button
              className="btn btn-sm btn-primary"
              style={{ fontSize: '0.75rem', padding: '3px 10px' }}
              disabled={paying}
              onClick={handlePay}
            >
              {paying ? (
                <span className="spinner-border spinner-border-sm me-1" />
              ) : (
                <i className="bi bi-credit-card me-1" />
              )}
              Pay Now
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
